const title = String(args.title ?? 'Revenue Overview');
const categories = Array.isArray(args.categories) && args.categories.length ? args.categories.map((item) => String(item)) : ['Jan', 'Feb', 'Mar'];
const values = Array.isArray(args.values) && args.values.length ? args.values.map((item) => Number(item) || 0) : [120, 168, 210];
const safeTitle = title.replace(/[<>]/g, '');
const html = `<!doctype html>
<html>
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>${safeTitle}</title>
    <script src="https://cdn.jsdelivr.net/npm/echarts@5/dist/echarts.min.js"></script>
    <style>
      body { margin: 0; font-family: 'Segoe UI', system-ui, sans-serif; background: #f4f7fb; color: #1f2937; }
      .wrap { max-width: 980px; margin: 0 auto; padding: 28px; }
      .hero { display: flex; justify-content: space-between; align-items: end; gap: 16px; margin-bottom: 20px; }
      h1 { margin: 0; font-size: 28px; line-height: 1.1; }
      p { margin: 6px 0 0; color: #6b7280; }
      .card { background: #ffffff; border: 1px solid #dbe3f0; border-radius: 20px; box-shadow: 0 16px 40px rgba(15, 23, 42, 0.08); overflow: hidden; }
      .card-head { padding: 18px 22px 0; font-size: 14px; color: #64748b; }
      #chart { height: 420px; }
    </style>
  </head>
  <body>
    <div class="wrap">
      <div class="hero">
        <div>
          <h1>${safeTitle}</h1>
          <p>Generated by a registry skill through callTool('generate_chart', ...).</p>
        </div>
      </div>
      <section class="card">
        <div class="card-head">Monthly revenue trend</div>
        <div id="chart"></div>
      </section>
    </div>
    <script>
      document.addEventListener('DOMContentLoaded', function () {
        var chart = echarts.init(document.getElementById('chart'));
        chart.setOption({
          animationDuration: 700,
          grid: { top: 40, right: 24, bottom: 32, left: 48 },
          tooltip: { trigger: 'axis' },
          xAxis: { type: 'category', data: ${JSON.stringify(categories)}, axisTick: { alignWithLabel: true } },
          yAxis: { type: 'value', splitLine: { lineStyle: { color: '#e5e7eb' } } },
          series: [{
            type: 'bar',
            data: ${JSON.stringify(values)},
            barWidth: '42%',
            itemStyle: { color: '#2563eb', borderRadius: [10, 10, 0, 0] }
          }]
        });
      });
    <\/script>
  </body>
</html>`;
return await callTool('generate_chart', { html, title: safeTitle });
